import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators, ReactiveFormsModule } from '@angular/forms';
import { Router, RouterModule } from '@angular/router';
import { CommonModule } from '@angular/common';
import { ParkaddaAuthService } from '../../../services/parkadda-auth.service';

@Component({
  standalone: true,
  selector: 'app-parkadda-login',
  imports: [ReactiveFormsModule, CommonModule, RouterModule],
  template: `
  <div class="login-wrapper">
    <div class="login-left">
      <img src="/IMG_20251203_100849.jpg" alt="hero" class="left-image" />
    </div>

    <div class="login-right">
      <div class="login-box">
        <h2>Parkadda Admin Login</h2>
        <p class="subtitle">Parking Management System</p>

        <form [formGroup]="loginForm" (ngSubmit)="onSubmit()">
          <div class="form-group" [class.invalid]="isInvalid('mobile')">
            <label><i class="fa fa-phone"></i> Mobile Number</label>
            <input type="tel" formControlName="mobile" placeholder="Enter mobile number" />
            <small *ngIf="isInvalid('mobile')">Mobile number is required</small>
          </div>

          <div class="form-group" [class.invalid]="isInvalid('password')">
            <label><i class="fa fa-lock"></i> Password</label>
            <input type="password" formControlName="password" placeholder="Enter password" />
            <small *ngIf="isInvalid('password')">Password is required</small>
          </div>

          <div *ngIf="error" class="error-message">
            <i class="fa fa-exclamation-circle"></i> {{ error }}
          </div>

          <button type="submit" [disabled]="loginForm.invalid || submitting" class="btn-login">
            {{ submitting ? 'Logging in...' : 'LOGIN' }}
          </button>
        </form>

        <div class="footer-text">
          <p>Parkadda Admin Portal</p>
        </div>

        <div class="social-icons">
          <span class="circle blue"></span>
          <span class="circle red"></span>
          <span class="circle pink"></span>
        </div>
      </div>
    </div>
  </div>
  `,
  styles: [`
    .login-wrapper {
      display: flex;
      height: 100vh;
      font-family: 'Poppins', sans-serif;
      background: #f3f6fa;
    }
    .login-left {
      flex: 1;
      display: block;
      overflow: hidden;
      background: #fff;
    }
    .left-image {
      width: 100%;
      height: 100%;
      object-fit: cover;
    }
    .login-right {
      flex: 1;
      display: flex;
      align-items: center;
      justify-content: center;
      background: white;
    }
    .login-box {
      width: 360px;
      padding: 30px;
      text-align: center;
      background: #fff;
      box-shadow: 0 4px 15px rgba(0,0,0,0.1);
      border-radius: 12px;
    }
    .login-box h2 {
      margin-bottom: 8px;
      font-size: 26px;
      font-weight: 600;
      color: #333;
    }
    .subtitle {
      margin-bottom: 24px;
      font-size: 13px;
      color: #999;
    }
    .form-group {
      text-align: left;
      margin-bottom: 18px;
      position: relative;
    }
    .form-group label {
      font-size: 14px;
      color: #555;
      display: block;
      margin-bottom: 5px;
    }
    .form-group input {
      width: 100%;
      padding: 10px;
      border: none;
      border-bottom: 2px solid #ccc;
      outline: none;
      font-size: 15px;
      transition: 0.3s;
      box-sizing: border-box;
    }
    .form-group.invalid input {
      border-bottom: 2px solid #ff5252;
    }
    .form-group small {
      color: #ff5252;
      font-size: 12px;
      position: absolute;
      bottom: -18px;
    }
    .form-group input:focus {
      border-bottom: 2px solid #007bff;
    }
    .error-message {
      background: #ffebee;
      color: #c62828;
      padding: 10px 12px;
      border-radius: 6px;
      font-size: 13px;
      margin-bottom: 16px;
      display: flex;
      align-items: center;
      gap: 8px;
      border-left: 3px solid #c62828;
    }
    .btn-login {
      width: 100%;
      padding: 12px;
      background: linear-gradient(to right, #00c6ff, #5a00ff);
      border: none;
      color: white;
      font-weight: 600;
      border-radius: 25px;
      cursor: pointer;
      margin-top: 20px;
      transition: 0.3s;
    }
    .btn-login:hover:not(:disabled) {
      opacity: 0.9;
      transform: translateY(-2px);
    }
    .btn-login:disabled {
      opacity: 0.6;
      cursor: not-allowed;
    }
    .footer-text {
      margin-top: 16px;
      font-size: 12px;
      color: #999;
    }
    .social-icons {
      display: flex;
      justify-content: center;
      gap: 12px;
      margin-top: 16px;
    }
    .circle {
      width: 30px;
      height: 30px;
      border-radius: 50%;
      cursor: pointer;
    }
    .circle.blue { background-color: #3b5998; }
    .circle.red { background-color: #00acee; }
    .circle.pink { background-color: #ea4c89; }
    @media (max-width: 768px) {
      .login-wrapper { flex-direction: column; }
      .login-left { display: none; }
      .login-box { width: 90%; }
    }
  `]
})
export class ParkaddaLoginComponent {
  loginForm: FormGroup;
  submitting = false;
  error: string | null = null;

  constructor(
    private fb: FormBuilder,
    private parkaddaAuthService: ParkaddaAuthService,
    private router: Router
  ) {
    this.loginForm = this.fb.group({
      mobile: ['', [Validators.required, Validators.minLength(10)]],
      password: ['', Validators.required]
    });
  }

  isInvalid(control: string): boolean {
    const ctrl = this.loginForm.get(control);
    return !!ctrl && ctrl.invalid && (ctrl.dirty || ctrl.touched);
  }

  onSubmit() {
    this.error = null;
    if (this.loginForm.valid) {
      const { mobile, password } = this.loginForm.value;
      this.submitting = true;

      this.parkaddaAuthService.adminLogin(mobile, password).subscribe({
        next: (res) => {
          // ✅ Token is automatically stored by service via tap operator
          this.submitting = false;
          // ✅ Navigate to Parkadda dashboard
          this.router.navigate(['/parkadda/dashboard']);
        },
        error: (err) => {
          this.error = err.message || 'Login failed. Please check your credentials.';
          this.submitting = false;
        },
        complete: () => (this.submitting = false)
      });
    }
  }
}
